import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type InlaySecuredShieldProps = IconProps;

const InlaySecuredShieldLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 12 12"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="M8.854 4.854a.5.5 0 1 0-.708-.708L5.5 6.793 4.354 5.646a.5.5 0 1 0-.708.708l1.5 1.5a.5.5 0 0 0 .708 0z"
      fill="#818594"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M11 6c0 4-5 6-5 6s-5-2-5-6V2l5-2 5 2zM2 6V2.677l4-1.6 4 1.6V6c0 1.552-.97 2.795-2.125 3.72A10.3 10.3 0 0 1 6 10.901 10.287 10.287 0 0 1 4.125 9.72C2.97 8.794 2 7.551 2 6"
      fill="#818594"
    />
  </svg>
);

const InlaySecuredShieldDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 12 12"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path
      d="M8.854 4.854a.5.5 0 1 0-.708-.708L5.5 6.793 4.354 5.646a.5.5 0 1 0-.708.708l1.5 1.5a.5.5 0 0 0 .708 0z"
      fill="#9DA0A8"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M11 6c0 4-5 6-5 6s-5-2-5-6V2l5-2 5 2zM2 6V2.677l4-1.6 4 1.6V6c0 1.552-.97 2.795-2.125 3.72A10.3 10.3 0 0 1 6 10.901 10.287 10.287 0 0 1 4.125 9.72C2.97 8.794 2 7.551 2 6"
      fill="#9DA0A8"
    />
  </svg>
);

export const InlaySecuredShield: FC<InlaySecuredShieldProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent =
    mode === 'light' ? InlaySecuredShieldLight : InlaySecuredShieldDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
